const fs = require('fs');
const draftsDir = $env.QUEUE_DRAFTS_PATH || '/data/voidai/queue/drafts/';
const post = $('Validate Input').first().json;
const slug = post.title.toLowerCase().replace(/[^a-z0-9]+/g, '-').slice(0, 40);
const date = new Date().toISOString().split('T')[0];

const results = [];

// 1. X Thread
try {
  const threadResponse = $('Claude: X Thread').first().json;
  const threadText = threadResponse?.content?.[0]?.text || '[]';
  let tweets = [];
  try {
    tweets = JSON.parse(threadText);
  } catch (e) {
    tweets = threadText.split('\n').filter(l => l.match(/^\d+\//));
  }

  const threadContent = `---\ntype: x-thread\naccount: "@v0idai"\nstatus: review\ncreated: ${new Date().toISOString()}\nsource: workflow-7-blog-distribution\nrequires_human_review: true\nblog_url: ${post.url}\ntweet_count: ${tweets.length}\n---\n\n# X Thread | ${post.title}\n\n${tweets.map((t, i) => `## Tweet ${i + 1}\n\n${typeof t === 'string' ? t : t.text || t}\n`).join('\n')}`;

  const threadFile = `${draftsDir}blog-deriv-x-thread-${slug}.md`;
  fs.mkdirSync(draftsDir, { recursive: true });
  fs.writeFileSync(threadFile, threadContent);
  results.push({ type: 'x-thread', file: threadFile, tweets: tweets.length });
} catch (e) {
  results.push({ type: 'x-thread', error: e.message });
}

// 2. LinkedIn Post
try {
  const liResponse = $('Claude: LinkedIn Post').first().json;
  const liText = liResponse?.content?.[0]?.text || '';

  const liContent = `---\ntype: linkedin\naccount: "voidai"\nstatus: review\ncreated: ${new Date().toISOString()}\nsource: workflow-7-blog-distribution\nrequires_human_review: true\nblog_url: ${post.url}\n---\n\n# LinkedIn Post | ${post.title}\n\n${liText}`;

  const liFile = `${draftsDir}blog-deriv-linkedin-${slug}.md`;
  fs.writeFileSync(liFile, liContent);
  results.push({ type: 'linkedin', file: liFile });
} catch (e) {
  results.push({ type: 'linkedin', error: e.message });
}

// 3. Discord Announcement
try {
  const dcResponse = $('Claude: Discord Announcement').first().json;
  const dcText = dcResponse?.content?.[0]?.text || '';

  const dcContent = `---\ntype: discord\naccount: "announcements"\nstatus: review\ncreated: ${new Date().toISOString()}\nsource: workflow-7-blog-distribution\nrequires_human_review: true\nblog_url: ${post.url}\n---\n\n# Discord Announcement | ${post.title}\n\n${dcText}`;

  const dcFile = `${draftsDir}blog-deriv-discord-${slug}.md`;
  fs.writeFileSync(dcFile, dcContent);
  results.push({ type: 'discord', file: dcFile });
} catch (e) {
  results.push({ type: 'discord', error: e.message });
}

return [{ json: {
  blog_title: post.title,
  derivatives_created: results.filter(r => !r.error).length,
  derivatives_failed: results.filter(r => r.error).length,
  results
} }];

